            {
                int u = arr[2 + 3 * i];
                int v = arr[2 + 3 * i + 1];
                int w = arr[2 + 3 * i + 2];

                if (u >= 0 && u < n && v >= 0 && v < n)
                {
                    if (w < dist[u, v])
                    {
                        dist[u, v] = w;
                    }
                }
            }

            for (int k = 0; k < n; k++)
            {
                for (int i = 0; i < n; i++)
                {
                    for (int j = 0; j < n; j++)
